+
+    public Session createSessionRequest(Long userId) {
+        Couple couple = coupleService.getCoupleByUserIdOrThrow(userId);
+
+        // 한 커플에 동시에 진행 중/대기 중 세션은 1개만 (원하면 정책 바꾸면 됨)
